SELECT id, sender_id, receiver_id, last_message, last_message_at, sender_deleted, receiver_deleted, created_at, updated_at
FROM message_threads
WHERE id = #{threadId}

SELECT COUNT(*)
FROM messages m
WHERE m.thread_id = #{threadId}
  AND m.receiver_id = #{userId}
  AND m.read_yn = FALSE
  AND m.deleted_by_receiver = FALSE
